// src/components/modals/OrderModal.js
import React, { useRef, useEffect, useState } from 'react';
import { PRODUCTS, UNIT_PRICES, STATUSES } from '../../utils/constants';

const COUNTRIES = [
  "Afghanistan","Albania","Algeria","Andorra","Angola","Antigua and Barbuda",
  "Argentina","Armenia","Australia","Austria","Azerbaijan","Bahamas","Bahrain",
  "Bangladesh","Barbados","Belarus","Belgium","Belize","Benin","Bhutan",
  "Bolivia","Bosnia and Herzegovina","Botswana","Brazil","Brunei","Bulgaria",
  "Burkina Faso","Burundi","Cabo Verde","Cambodia","Cameroon","Canada",
  "Central African Republic","Chad","Chile","China","Colombia","Comoros",
  "Congo (Congo-Brazzaville)","Costa Rica","Croatia","Cuba","Cyprus",
  "Czechia","Denmark","Djibouti","Dominica","Dominican Republic","Ecuador",
  "Egypt","El Salvador","Equatorial Guinea","Eritrea","Estonia","Eswatini",
  "Ethiopia","Fiji","Finland","France","Gabon","Gambia","Georgia","Germany",
  "Ghana","Greece","Grenada","Guatemala","Guinea","Guinea-Bissau","Guyana",
  "Haiti","Honduras","Hungary","Iceland","India","Indonesia","Iran","Iraq",
  "Ireland","Israel","Italy","Jamaica","Japan","Jordan","Kazakhstan","Kenya",
  "Kiribati","Kuwait","Kyrgyzstan","Laos","Latvia","Lebanon","Lesotho",
  "Liberia","Libya","Liechtenstein","Lithuania","Luxembourg","Madagascar",
  "Malawi","Malaysia","Maldives","Mali","Malta","Marshall Islands",
  "Mauritania","Mauritius","Mexico","Micronesia","Moldova","Monaco",
  "Mongolia","Montenegro","Morocco","Mozambique","Myanmar","Namibia","Nauru",
  "Nepal","Netherlands","New Zealand","Nicaragua","Niger","Nigeria",
  "North Korea","North Macedonia","Norway","Oman","Pakistan","Palau",
  "Palestine State","Panama","Papua New Guinea","Paraguay","Peru",
  "Philippines","Poland","Portugal","Qatar","Romania","Russia","Rwanda",
  "Saint Kitts and Nevis","Saint Lucia","Saint Vincent and the Grenadines",
  "Samoa","San Marino","Sao Tome and Principe","Saudi Arabia","Senegal",
  "Serbia","Seychelles","Sierra Leone","Singapore","Slovakia","Slovenia",
  "Solomon Islands","Somalia","South Africa","South Korea","South Sudan",
  "Spain","Sri Lanka","Sudan","Suriname","Sweden","Switzerland","Syria",
  "Tajikistan","Tanzania","Thailand","Timor-Leste","Togo","Tonga",
  "Trinidad and Tobago","Tunisia","Turkey","Turkmenistan","Tuvalu","Uganda",
  "Ukraine","United Arab Emirates","United Kingdom","United States",
  "Uruguay","Uzbekistan","Vanuatu","Vatican City","Venezuela","Vietnam",
  "Yemen","Zambia","Zimbabwe",
];

const CREATORS = [
  'Mr. Michael Harris',
  'Mr. Ryan Cooper',
  'Ms. Olivia Carter',
  'Mr. Lucas Martin',
];

const PHONE_CODES = [
  {code:'+91',flag:'🇮🇳',name:'IND'},{code:'+1',flag:'🇺🇸',name:'USA'},
  {code:'+1',flag:'🇨🇦',name:'CAN'},{code:'+44',flag:'🇬🇧',name:'GBR'},
  {code:'+61',flag:'🇦🇺',name:'AUS'},{code:'+64',flag:'🇳🇿',name:'NZL'},
  {code:'+65',flag:'🇸🇬',name:'SGP'},{code:'+852',flag:'🇭🇰',name:'HKG'},
  {code:'+81',flag:'🇯🇵',name:'JPN'},{code:'+82',flag:'🇰🇷',name:'KOR'},
  {code:'+86',flag:'🇨🇳',name:'CHN'},{code:'+49',flag:'🇩🇪',name:'DEU'},
  {code:'+33',flag:'🇫🇷',name:'FRA'},{code:'+39',flag:'🇮🇹',name:'ITA'},
  {code:'+34',flag:'🇪🇸',name:'ESP'},{code:'+31',flag:'🇳🇱',name:'NLD'},
  {code:'+46',flag:'🇸🇪',name:'SWE'},{code:'+47',flag:'🇳🇴',name:'NOR'},
  {code:'+45',flag:'🇩🇰',name:'DNK'},{code:'+358',flag:'🇫🇮',name:'FIN'},
  {code:'+41',flag:'🇨🇭',name:'CHE'},{code:'+43',flag:'🇦🇹',name:'AUT'},
  {code:'+32',flag:'🇧🇪',name:'BEL'},{code:'+351',flag:'🇵🇹',name:'PRT'},
  {code:'+30',flag:'🇬🇷',name:'GRC'},{code:'+48',flag:'🇵🇱',name:'POL'},
  {code:'+420',flag:'🇨🇿',name:'CZE'},{code:'+36',flag:'🇭🇺',name:'HUN'},
  {code:'+40',flag:'🇷🇴',name:'ROU'},{code:'+7',flag:'🇷🇺',name:'RUS'},
  {code:'+380',flag:'🇺🇦',name:'UKR'},{code:'+90',flag:'🇹🇷',name:'TUR'},
  {code:'+966',flag:'🇸🇦',name:'SAU'},{code:'+971',flag:'🇦🇪',name:'ARE'},
  {code:'+974',flag:'🇶🇦',name:'QAT'},{code:'+973',flag:'🇧🇭',name:'BHR'},
  {code:'+965',flag:'🇰🇼',name:'KWT'},{code:'+968',flag:'🇴🇲',name:'OMN'},
  {code:'+972',flag:'🇮🇱',name:'ISR'},{code:'+20',flag:'🇪🇬',name:'EGY'},
  {code:'+27',flag:'🇿🇦',name:'ZAF'},{code:'+234',flag:'🇳🇬',name:'NGA'},
  {code:'+254',flag:'🇰🇪',name:'KEN'},{code:'+233',flag:'🇬🇭',name:'GHA'},
  {code:'+55',flag:'🇧🇷',name:'BRA'},{code:'+52',flag:'🇲🇽',name:'MEX'},
  {code:'+54',flag:'🇦🇷',name:'ARG'},{code:'+57',flag:'🇨🇴',name:'COL'},
  {code:'+56',flag:'🇨🇱',name:'CHL'},{code:'+51',flag:'🇵🇪',name:'PER'},
  {code:'+60',flag:'🇲🇾',name:'MYS'},{code:'+62',flag:'🇮🇩',name:'IDN'},
  {code:'+63',flag:'🇵🇭',name:'PHL'},{code:'+66',flag:'🇹🇭',name:'THA'},
  {code:'+84',flag:'🇻🇳',name:'VNM'},{code:'+92',flag:'🇵🇰',name:'PAK'},
  {code:'+880',flag:'🇧🇩',name:'BGD'},{code:'+94',flag:'🇱🇰',name:'LKA'},
  {code:'+977',flag:'🇳🇵',name:'NPL'},{code:'+98',flag:'🇮🇷',name:'IRN'},
];

function calcTotal(q, p) {
  const qty   = Math.max(1, parseInt(q, 10) || 1);
  const price = Math.max(0, parseFloat(p)   || 0);
  return qty * price;
}

function liveValidate(key, val) {
  if (!val || !String(val).trim()) return 'Please fill the field';
  if (key === 'email' && !/^[^@]+@[^@]+\.[^@]+$/.test(val)) return 'Enter a valid email';
  return '';
}

export default function OrderModal({ order, onClose, onSave }) {
  const isEdit = !!order;

  const r = {
    firstName:  useRef(null), lastName:   useRef(null),
    email:      useRef(null), phone:      useRef(null),
    street:     useRef(null), city:       useRef(null),
    stateVal:   useRef(null), postalCode: useRef(null),
    country:    useRef(null), product:    useRef(null),
    quantity:   useRef(null), unitPrice:  useRef(null),
    status:     useRef(null), createdBy:  useRef(null),
    orderDate:  useRef(null),
  };

  const [qty,          setQty]          = useState(1);
  const [unitPriceVal, setUnitPriceVal] = useState(2999);
  const [errs,         setErrs]         = useState({});
  const [saving,       setSaving]       = useState(false);
  const [dialCode,     setDialCode]     = useState('+91');

  useEffect(() => {
    const src = order || {};
    const set = (ref, val) => { if (ref.current) ref.current.value = val ?? ''; };
    set(r.firstName, src.firstName || '');
    set(r.lastName,  src.lastName  || '');
    set(r.email,     src.email     || '');
    if (src.phone) {
      const match = PHONE_CODES.find(p => src.phone.startsWith(p.code + ' '));
      if (match) { setDialCode(match.code); set(r.phone, src.phone.replace(match.code + ' ', '')); }
      else { set(r.phone, src.phone); }
    }
    set(r.street,    src.street     || '');
    set(r.city,      src.city       || '');
    set(r.stateVal,  src.state      || '');
    set(r.postalCode,src.postalCode || '');
    set(r.country,   src.country    || 'United States');
    set(r.product,   src.product    || 'Fiber Internet 300 Mbps');
    set(r.quantity,  src.quantity   || 1);
    set(r.unitPrice, src.unitPrice  || UNIT_PRICES['Fiber Internet 300 Mbps']);
    setQty(src.quantity  || 1);
    setUnitPriceVal(src.unitPrice || UNIT_PRICES['Fiber Internet 300 Mbps']);
    set(r.status,    src.status    || 'Pending');
    set(r.createdBy, src.createdBy || 'Mr. Michael Harris');
    set(r.orderDate, src.orderDate ? String(src.orderDate).slice(0,10) : new Date().toISOString().slice(0,10));
  }, []); // eslint-disable-line

  function handleProduct(e) {
    const price = UNIT_PRICES[e.target.value] || 0;
    if (r.unitPrice.current) r.unitPrice.current.value = price;
    setUnitPriceVal(price);
  }

  function getVals() {
    return {
      firstName:  r.firstName.current?.value  || '',
      lastName:   r.lastName.current?.value   || '',
      email:      r.email.current?.value      || '',
      phone:      (dialCode + ' ' + (r.phone.current?.value || '')).trim(),
      street:     r.street.current?.value     || '',
      city:       r.city.current?.value       || '',
      state:      r.stateVal.current?.value   || '',
      postalCode: r.postalCode.current?.value || '',
      country:    r.country.current?.value    || 'United States',
      product:    r.product.current?.value    || '',
      quantity:   qty,
      unitPrice:  unitPriceVal,
      status:     r.status.current?.value     || 'Pending',
      createdBy:  r.createdBy.current?.value  || '',
      orderDate:  r.orderDate.current?.value  || '',
    };
  }

  function validate(v) {
    const e = {};
    if (!v.firstName.trim()) e.firstName  = 'Please fill the field';
    if (!v.lastName.trim())  e.lastName   = 'Please fill the field';
    if (!v.email.trim())     e.email      = 'Please fill the field';
    else if (!/^[^@]+@[^@]+\.[^@]+$/.test(v.email)) e.email = 'Enter a valid email';
    if (!v.phone.trim() || v.phone.trim() === dialCode) e.phone = 'Please fill the field';
    if (!v.street.trim())    e.street     = 'Please fill the field';
    if (!v.city.trim())      e.city       = 'Please fill the field';
    if (!v.state.trim())     e.stateVal   = 'Please fill the field';
    if (!v.postalCode.trim())e.postalCode = 'Please fill the field';
    if (v.quantity < 1)      e.quantity   = 'Min 1';
    return e;
  }

  async function submit(e) {
    e.preventDefault();
    const v = getVals();
    const ev = validate(v);
    if (Object.keys(ev).length) { setErrs(ev); return; }
    setSaving(true);
    try {
      await onSave({ ...v, totalAmount: calcTotal(v.quantity, v.unitPrice) });
      onClose();
    } catch(err) {
      setErrs({ _: err.message });
    } finally {
      setSaving(false);
    }
  }

  // Input styles
  const IS = (key) => {
    const hasErr = !!errs[key];
    const ref = r[key];
    const hasVal = ref?.current?.value?.trim();
    return {
      background: '#fff',
      border: `1.5px solid ${hasErr ? '#f43f5e' : hasVal ? '#10b981' : 'var(--border2)'}`,
      borderRadius: 'var(--r1)',
      padding: '10px 13px',
      color: 'var(--t1)',
      fontFamily: 'var(--ff-b)',
      fontSize: '13px',
      width: '100%',
      outline: 'none',
      transition: 'border-color .2s, box-shadow .2s',
      boxSizing: 'border-box',
    };
  };

  const SS = {
    background: '#fff',
    border: '1.5px solid var(--border2)',
    borderRadius: 'var(--r1)',
    padding: '10px 13px',
    color: 'var(--t1)',
    fontFamily: 'var(--ff-b)',
    fontSize: '13px',
    width: '100%',
    outline: 'none',
    cursor: 'pointer',
    boxSizing: 'border-box',
  };

  const onF  = e => { e.target.style.borderColor = 'var(--accent)'; e.target.style.boxShadow = '0 0 0 3px rgba(99,102,241,.1)'; };
  const onBS = e => { e.target.style.borderColor = 'var(--border2)'; e.target.style.boxShadow = 'none'; };
  const onBE = (key) => e => {
    const hasErr = !!errs[key];
    const hasVal = e.target.value?.trim();
    e.target.style.borderColor = hasErr ? '#f43f5e' : hasVal ? '#10b981' : 'var(--border2)';
    e.target.style.boxShadow = 'none';
  };

  // Field wrapper
  const F = ({ name, label, full, children }) => (
    <div style={full ? { gridColumn: '1 / -1' } : {}}>
      <label style={{ display:'block', fontSize:'11px', fontWeight:600, color:'var(--t2)', marginBottom:5, letterSpacing:'.02em' }}>
        {label} <span style={{ color:'#f43f5e' }}>*</span>
      </label>
      {children}
      {errs[name] ? (
        <span style={{ fontSize:'11px', color:'#f43f5e', marginTop:3, display:'flex', alignItems:'center', gap:3, fontWeight:500 }}>
          <span style={{ fontSize:9 }}>●</span> {errs[name]}
        </span>
      ) : null}
    </div>
  );

  return (
    <div className="overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal modal-xl" onClick={e => e.stopPropagation()}>

        <div style={{ height:3, background:'linear-gradient(90deg,#10b981,#06b6d4,#6366f1)', borderRadius:'var(--r3) var(--r3) 0 0' }} />

        <div className="modal-hd">
          <div>
            <h2>{isEdit ? 'Edit Order' : 'Create Order'}</h2>
            <p style={{ fontSize:12, color:'var(--t3)', marginTop:3 }}>All fields marked * are mandatory</p>
          </div>
          <button className="btn-icon" type="button" onClick={onClose}>✕</button>
        </div>

        <form onSubmit={submit}>
          <div className="modal-body">

            {errs._ && (
              <div style={{ background:'#fef2f2', border:'1px solid #fecaca', borderRadius:'var(--r1)', padding:'10px 14px', color:'#f43f5e', fontSize:13 }}>
                {errs._}
              </div>
            )}

            {/* ── CUSTOMER INFORMATION ── */}
            <div>
              <div className="section-title">Customer Information</div>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14 }}>

                <F name="firstName" label="First Name">
                  <input ref={r.firstName} type="text" placeholder="First name" defaultValue=""
                    style={IS('firstName')} onFocus={onF} onBlur={onBE('firstName')}
                    onChange={e => setErrs(p => ({ ...p, firstName: liveValidate('firstName', e.target.value) }))}
                    autoComplete="given-name" />
                </F>

                <F name="lastName" label="Last Name">
                  <input ref={r.lastName} type="text" placeholder="Last name" defaultValue=""
                    style={IS('lastName')} onFocus={onF} onBlur={onBE('lastName')}
                    onChange={e => setErrs(p => ({ ...p, lastName: liveValidate('lastName', e.target.value) }))}
                    autoComplete="family-name" />
                </F>

                <F name="email" label="Email ID">
                  <input ref={r.email} type="email" placeholder="email@example.com" defaultValue=""
                    style={IS('email')} onFocus={onF} onBlur={onBE('email')}
                    onChange={e => setErrs(p => ({ ...p, email: liveValidate('email', e.target.value) }))}
                    autoComplete="email" />
                </F>

                <F name="phone" label="Phone Number">
                  <div style={{
                    display:'flex', gap:0,
                    border: `1.5px solid ${errs.phone ? '#f43f5e' : 'var(--border2)'}`,
                    borderRadius:'var(--r1)', overflow:'hidden', background:'#fff',
                    transition:'border-color .2s, box-shadow .2s',
                  }}
                    onFocusCapture={e => { e.currentTarget.style.borderColor = 'var(--accent)'; e.currentTarget.style.boxShadow = '0 0 0 3px rgba(99,102,241,.1)'; }}
                    onBlurCapture={e  => { e.currentTarget.style.borderColor = errs.phone ? '#f43f5e' : 'var(--border2)'; e.currentTarget.style.boxShadow = 'none'; }}
                  >
                    <select value={dialCode} onChange={e => setDialCode(e.target.value)}
                      style={{ border:'none', outline:'none', background:'#f8fafc', borderRight:'1px solid var(--border2)', padding:'10px 6px 10px 10px', fontFamily:'var(--ff-b)', fontSize:'13px', color:'var(--t1)', cursor:'pointer', flexShrink:0, minWidth:90, fontWeight:600 }}>
                      {PHONE_CODES.map((p, i) => (
                        <option key={i} value={p.code}>{p.flag} {p.code} {p.name}</option>
                      ))}
                    </select>
                    <input ref={r.phone} type="tel" placeholder="9876543210" defaultValue=""
                      style={{ flex:1, border:'none', outline:'none', padding:'10px 13px', fontFamily:'var(--ff-b)', fontSize:'13px', color:'var(--t1)', background:'transparent', minWidth:0 }}
                      onChange={e => setErrs(p => ({ ...p, phone: e.target.value.trim() ? '' : 'Please fill the field' }))}
                      autoComplete="tel-national" />
                  </div>
                  {errs.phone && (
                    <span style={{ fontSize:'11px', color:'#f43f5e', marginTop:3, display:'flex', alignItems:'center', gap:3, fontWeight:500 }}>
                      <span style={{ fontSize:9 }}>●</span> {errs.phone}
                    </span>
                  )}
                </F>

                <F name="street" label="Street Address" full>
                  <input ref={r.street} type="text" placeholder="123 Main Street, Area" defaultValue=""
                    style={IS('street')} onFocus={onF} onBlur={onBE('street')}
                    onChange={e => setErrs(p => ({ ...p, street: liveValidate('street', e.target.value) }))}
                    autoComplete="street-address" />
                </F>

                <F name="city" label="City">
                  <input ref={r.city} type="text" placeholder="City" defaultValue=""
                    style={IS('city')} onFocus={onF} onBlur={onBE('city')}
                    onChange={e => setErrs(p => ({ ...p, city: liveValidate('city', e.target.value) }))} />
                </F>

                <F name="stateVal" label="State / Province">
                  <input ref={r.stateVal} type="text" placeholder="State" defaultValue=""
                    style={IS('stateVal')} onFocus={onF} onBlur={onBE('stateVal')}
                    onChange={e => setErrs(p => ({ ...p, stateVal: liveValidate('stateVal', e.target.value) }))} />
                </F>

                <F name="postalCode" label="Postal Code">
                  <input ref={r.postalCode} type="text" placeholder="600001" defaultValue=""
                    style={IS('postalCode')} onFocus={onF} onBlur={onBE('postalCode')}
                    onChange={e => setErrs(p => ({ ...p, postalCode: liveValidate('postalCode', e.target.value) }))} />
                </F>

                <F name="country" label="Country">
                  <select ref={r.country} defaultValue="United States" style={SS} onFocus={onF} onBlur={onBS}>
                    {COUNTRIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </F>

              </div>
            </div>

            {/* ── ORDER INFORMATION ── */}
            <div>
              <div className="section-title">Order Information</div>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14 }}>

                <F name="product" label="Choose Product" full>
                  <select ref={r.product} defaultValue="Fiber Internet 300 Mbps" style={SS} onChange={handleProduct} onFocus={onF} onBlur={onBS}>
                    {PRODUCTS.map(p => <option key={p} value={p}>{p}</option>)}
                  </select>
                </F>

                <F name="quantity" label="Quantity">
                  <div style={{ display:'flex', alignItems:'center', gap:0, border:'1.5px solid var(--border2)', borderRadius:'var(--r1)', overflow:'hidden', background:'#fff', height:42 }}>
                    <button type="button"
                      onClick={() => setQty(q => Math.max(1, q - 1))}
                      style={{ width:48, height:'100%', background:'#f8fafc', border:'none', borderRight:'1px solid var(--border2)', cursor:'pointer', fontSize:20, fontWeight:600, color:'var(--t1)', flexShrink:0, transition:'background .15s', userSelect:'none' }}
                      onMouseEnter={e => e.currentTarget.style.background = '#e2e8f0'}
                      onMouseLeave={e => e.currentTarget.style.background = '#f8fafc'}>
                      −
                    </button>
                    <input type="number" min="1" value={qty}
                      onChange={e => setQty(Math.max(1, parseInt(e.target.value, 10) || 1))}
                      style={{ flex:1, border:'none', outline:'none', textAlign:'center', fontWeight:800, fontSize:'17px', fontFamily:'var(--ff-b)', color:'var(--t1)', background:'transparent', padding:'0 4px' }} />
                    <button type="button"
                      onClick={() => setQty(q => q + 1)}
                      style={{ width:48, height:'100%', background:'#f8fafc', border:'none', borderLeft:'1px solid var(--border2)', cursor:'pointer', fontSize:20, fontWeight:600, color:'var(--t1)', flexShrink:0, transition:'background .15s', userSelect:'none' }}
                      onMouseEnter={e => e.currentTarget.style.background = '#e2e8f0'}
                      onMouseLeave={e => e.currentTarget.style.background = '#f8fafc'}>
                      +
                    </button>
                  </div>
                </F>

                <F name="unitPrice" label="Unit Price ($)">
                  <div style={{ position:'relative' }}>
                    <span style={{ position:'absolute', left:12, top:'50%', transform:'translateY(-50%)', color:'var(--t3)', fontSize:13, pointerEvents:'none', fontWeight:600 }}>$</span>
                    <input type="number" min="0" step="1" value={unitPriceVal}
                      onChange={e => setUnitPriceVal(Math.max(0, parseFloat(e.target.value) || 0))}
                      onFocus={onF} onBlur={onBS}
                      style={{ ...IS(null), paddingLeft:28, fontSize:14, fontWeight:600 }} />
                  </div>
                </F>

                <F name="totalAmount" label="Total Amount (Read Only — Qty × Unit Price)">
                  <div style={{ background:'#f0fdf4', border:'1.5px solid #86efac', borderRadius:'var(--r1)', padding:'11px 16px', display:'flex', alignItems:'center', gap:6 }}>
                    <span style={{ fontSize:15, color:'#10b981', fontWeight:600 }}>$</span>
                    <span style={{ fontSize:18, fontWeight:800, fontFamily:'var(--ff-h)', color:'#10b981', letterSpacing:'-0.02em' }}>
                      {(qty * unitPriceVal).toLocaleString('en-US', { minimumFractionDigits:2 })}
                    </span>
                    <span style={{ fontSize:11, color:'#86efac', marginLeft:4 }}>{qty} × ${unitPriceVal.toLocaleString('en-US')}</span>
                  </div>
                </F>

                <F name="status" label="Status">
                  <select ref={r.status} defaultValue="Pending" style={SS} onFocus={onF} onBlur={onBS}>
                    {STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </F>

                <F name="createdBy" label="Created By">
                  <select ref={r.createdBy} defaultValue="Mr. Michael Harris" style={SS} onFocus={onF} onBlur={onBS}>
                    {CREATORS.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </F>

              </div>
            </div>

          </div>

          <div className="modal-ft">
            <button className="btn btn-ghost" type="button" onClick={onClose}>Cancel</button>
            <button className="btn btn-primary" type="submit" disabled={saving} style={{ minWidth:130, justifyContent:'center' }}>
              {saving ? <><span className="spinner" />Saving…</> : isEdit ? 'Update Order' : 'Create Order'}
            </button>
          </div>
        </form>

      </div>
    </div>
  );
}
